INSERT INTO myus.FAQArticle (question, answer, category, tags, published) VALUES
(N'Cách đăng ký học phần trực tuyến?', N'Sinh viên truy cập vào mục Đăng ký học phần, chọn môn học trong danh sách Course Offerings và nhấn Đăng ký.', N'Đào tạo', N'dangkymon, hocphan', 1),
(N'Làm sao để phúc khảo điểm môn học?', N'Vào mục Grade Appeal / Phúc khảo, chọn môn học cần phúc khảo, nhập lý do và đính kèm minh chứng.', N'Khảo thí', N'phuckhao, diem', 1),
(N'Quy trình đóng học phí trực tuyến?', N'Sinh viên xem công nợ tại Học phí, chuyển khoản theo cú pháp MSSV - HocPhiHKx tới tài khoản Đại học Khoa học Tự nhiên.', N'Tài chính', N'hocphi, thanhtoan', 1);
